import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../App';
import './Register.css';

export default function Register() {
  const { register } = useAuth();
  const navigate = useNavigate();
  const [form, setForm] = useState({
    name: '', email: '', password: '', confirmPassword: '',
    role: 'patient', phone: '', specialization: '', department: '', otp: ''
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [otpSent, setOtpSent] = useState(false);

  const update = (field) => (e) => setForm({ ...form, [field]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    if (form.password.length < 8) {
      setError('Password must be at least 8 characters');
      return;
    }
    if (form.password !== form.confirmPassword) {
      setError('Passwords do not match');
      return;
    }
    if (!otpSent) {
      setError('Please request an OTP first');
      return;
    }
    if (!form.otp) {
      setError('Please enter the OTP sent to your email');
      return;
    }

    setLoading(true);
    try {
      await register(form);
      navigate('/login');
    } catch (err) {
      setError(err.response?.data?.error || 'Registration failed');
    } finally {
      setLoading(false);
    }
  };

  const handleSendOtp = async () => {
    if (!form.email) {
      setError('Please enter your email first');
      return;
    }
    setError('');
    try {
      await fetch('http://localhost:5000/api/send-otp', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: form.email })
      }).then(async res => {
          if (!res.ok) {
              const err = await res.json();
              throw new Error(err.error || 'Failed to send OTP');
          }
          return res.json();
      });
      setOtpSent(true);
      setError('OTP sent to your email. Check console (mock email).');
    } catch (err) {
      setError(err.message || 'Failed to send OTP');
    }
  };

  return (
    <div className="register-wrapper">
      <div className="register-card">
        <h1 className="register-title">🏥 Create Account</h1>
        <p className="register-subtitle">Join Arogya and manage your health appointments</p>

        {error && <div className="register-error">{error}</div>}

        <form onSubmit={handleSubmit}>
          <div className="register-form-row">
            <div className="register-form-group">
              <label>Full Name *</label>
              <input type="text" value={form.name} onChange={update('name')} placeholder="John Doe" required />
            </div>
            <div className="register-form-group">
              <label>Email Address *</label>
              <div style={{display:'flex', gap:'0.5rem'}}>
                <input type="email" value={form.email} onChange={update('email')} placeholder="you@email.com" required style={{flex: 1}} disabled={otpSent} />
                {!otpSent && (
                  <button type="button" onClick={handleSendOtp} className="register-btn" style={{marginTop: 0, width: 'auto', padding: '0.65rem 1rem'}}>Send OTP</button>
                )}
              </div>
            </div>
          </div>

          <div className="register-form-row">
            <div className="register-form-group">
              <label>Password *</label>
              <input type="password" value={form.password} onChange={update('password')} placeholder="Min 8 characters" required />
            </div>
            <div className="register-form-group">
              <label>Confirm Password *</label>
              <input type="password" value={form.confirmPassword} onChange={update('confirmPassword')} placeholder="Re-enter password" required />
            </div>
          </div>

          <div className="register-form-row">
            <div className="register-form-group">
              <label>Phone</label>
              <input type="tel" value={form.phone} onChange={update('phone')} placeholder="+91 9876543210" />
            </div>
            <div className="register-form-group">
              <label>Register as *</label>
              <select value={form.role} onChange={update('role')}>
                <option value="patient">Patient</option>
                <option value="doctor">Doctor</option>
              </select>
            </div>
          </div>

          {form.role === 'doctor' && (
            <div className="register-form-row">
              <div className="register-form-group">
                <label>Specialization *</label>
                <select value={form.specialization} onChange={update('specialization')} required>
                  <option value="">Select</option>
                  <option value="Cardiology">Cardiology</option>
                  <option value="Dermatology">Dermatology</option>
                  <option value="Neurology">Neurology</option>
                  <option value="Orthopedics">Orthopedics</option>
                  <option value="Pediatrics">Pediatrics</option>
                  <option value="Gynecology">Gynecology</option>
                  <option value="General Medicine">General Medicine</option>
                  <option value="ENT">ENT</option>
                  <option value="Ophthalmology">Ophthalmology</option>
                  <option value="Dentistry">Dentistry</option>
                </select>
              </div>
              <div className="register-form-group">
                <label>Department *</label>
                <select value={form.department} onChange={update('department')} required>
                  <option value="">Select</option>
                  <option value="Cardiology">Cardiology</option>
                  <option value="Dermatology">Dermatology</option>
                  <option value="Neurology">Neurology</option>
                  <option value="Orthopedics">Orthopedics</option>
                  <option value="Pediatrics">Pediatrics</option>
                  <option value="General Medicine">General Medicine</option>
                  <option value="ENT">ENT</option>
                </select>
              </div>
            </div>
          )}

          {otpSent && (
            <div className="register-form-row">
              <div className="register-form-group">
                <label>Enter OTP *</label>
                <input type="text" value={form.otp} onChange={update('otp')} placeholder="6-digit code" required maxLength={6} />
              </div>
            </div>
          )}

          <button type="submit" className="register-btn" disabled={loading || !otpSent}>
            {loading ? 'Creating Account...' : 'Verify & Create Account'}
          </button>
        </form>

        <p className="register-footer">
          Already have an account? <Link to="/login">Sign In</Link>
        </p>
      </div>
    </div>
  );
}
